export function init(dropZoneElement, dotNetHelper) {
    function onDragOver(e) {
        e.preventDefault();
        dropZoneElement.classList.add('drag-over');
    }

    function onDragLeave(e) {
        e.preventDefault();
        dropZoneElement.classList.remove('drag-over');
    }

    function onDrop(e) {
        e.preventDefault();
        dropZoneElement.classList.remove('drag-over');

        const files = [];
        for (const file of e.dataTransfer.files) {
            files.push({ name: file.name, size: file.size, type: file.type || 'application/octet-stream' });
        }

        dotNetHelper.invokeMethodAsync('OnFilesDropped', files);
    }

    dropZoneElement.addEventListener('dragover', onDragOver);
    dropZoneElement.addEventListener('dragleave', onDragLeave);
    dropZoneElement.addEventListener('drop', onDrop);

    return {
        dispose: () => {
            dropZoneElement.removeEventListener('dragover', onDragOver);
            dropZoneElement.removeEventListener('dragleave', onDragLeave);
            dropZoneElement.removeEventListener('drop', onDrop);
        }
    };
}

@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_dropZoneRef" class="drop-zone">
    <p>Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _files)
        {
            <li>
                @if (entry.IsOversize)
                {
                    <span class="file-error">
                        &#9888; <strong>@entry.Info.Name</strong> &mdash; @FormatSize(entry.Info.Size)
                        exceeds the 10 MB limit
                    </span>
                }
                else
                {
                    <span class="file-info">
                        <strong>@entry.Info.Name</strong> &mdash; @FormatSize(entry.Info.Size) &mdash; @entry.Info.Type
                    </span>
                }
                <button class="btn-remove" @onclick="() => Remove(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSize = 10L * 1024 * 1024;

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private IJSObjectReference? _instance;
    private readonly List<FileEntry> _files = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>("import", "./fileDropZone.js");
            _instance = await _module.InvokeAsync<IJSObjectReference>("init", _dropZoneRef,
                DotNetObjectReference.Create(this));
        }
    }

    [JSInvokable]
    public async Task OnFilesDropped(List<DroppedFile> droppedFiles)
    {
        foreach (var f in droppedFiles)
        {
            var info = new FileInfo(f.Name, f.Size, f.Type);
            _files.Add(new FileEntry(info, f.Size > MaxFileSize));
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task Remove(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private Task NotifyParent()
    {
        var accepted = _files.Where(f => !f.IsOversize).Select(f => f.Info).ToList();
        return OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_instance is not null)
        {
            await _instance.InvokeVoidAsync("dispose");
            await _instance.DisposeAsync();
        }
        if (_module is not null)
            await _module.DisposeAsync();
    }

    public record DroppedFile(string Name, long Size, string Type);
    private record FileEntry(FileInfo Info, bool IsOversize);
}

.drop-zone {
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 3rem 2rem;
    text-align: center;
    color: #6c757d;
    background-color: #f8f9fa;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
}

::deep .drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
    color: #0d6efd;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-list li {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-info {
    color: #212529;
}

.file-error {
    color: #dc3545;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.2rem 0.6rem;
    cursor: pointer;
    margin-left: 1rem;
    font-size: 0.875rem;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

