@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_dropZoneRef" class="drop-zone">
    <p>Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _files)
        {
            <li>
                @if (entry.IsOversize)
                {
                    <span class="file-error">
                        &#9888; <strong>@entry.Info.Name</strong> &mdash; @FormatSize(entry.Info.Size)
                        exceeds the 10 MB limit
                    </span>
                }
                else
                {
                    <span class="file-info">
                        <strong>@entry.Info.Name</strong> &mdash; @FormatSize(entry.Info.Size) &mdash; @entry.Info.Type
                    </span>
                }
                <button class="btn-remove" @onclick="() => Remove(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSize = 10L * 1024 * 1024;

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private IJSObjectReference? _instance;
    private readonly List<FileEntry> _files = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>("import", "./fileDropZone.js");
            _instance = await _module.InvokeAsync<IJSObjectReference>("init", _dropZoneRef,
                DotNetObjectReference.Create(this));
        }
    }

    [JSInvokable]
    public async Task OnFilesDropped(List<DroppedFile> droppedFiles)
    {
        foreach (var f in droppedFiles)
        {
            var info = new FileInfo(f.Name, f.Size, f.Type);
            _files.Add(new FileEntry(info, f.Size > MaxFileSize));
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task Remove(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private Task NotifyParent()
    {
        var accepted = _files.Where(f => !f.IsOversize).Select(f => f.Info).ToList();
        return OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_instance is not null)
        {
            await _instance.InvokeVoidAsync("dispose");
            await _instance.DisposeAsync();
        }
        if (_module is not null)
            await _module.DisposeAsync();
    }

    public record DroppedFile(string Name, long Size, string Type);
    private record FileEntry(FileInfo Info, bool IsOversize);
}

