toolArgs.file_text:
.drop-zone {
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 3rem 2rem;
    text-align: center;
    color: #6c757d;
    background-color: #f8f9fa;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
}

::deep .drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
    color: #0d6efd;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-list li {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-info {
    color: #212529;
}

.file-error {
    color: #dc3545;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.2rem 0.6rem;
    cursor: pointer;
    margin-left: 1rem;
    font-size: 0.875rem;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

